/**
 * Simplified Phi Calculator for Bootstrap-v15
 * 
 * Based on Integrated Information Theory (IIT) - Giulio Tononi
 * Phi (Φ) measures integrated information: information generated by the whole
 * that exceeds information generated by its parts.
 * 
 * Simplified approach for computational systems:
 * Φ ≈ log2(states_system) / (Σ log2(states_subsystems)) - 1
 * 
 * Where:
 * - states_system = total possible configurations of the whole
 * - states_subsystems = configurations when partitioned
 * 
 * For computational substrates, we approximate using:
 * - Component count and complexity
 * - Connectivity/interdependence between components
 * - Information flow capacity
 */

interface Component {
  name: string;
  stateSpaceSize: number;  // Number of distinct states this component can be in
  outputs: string[];       // Components it can influence
  inputs: string[];        // Components that influence it
}

interface SystemState {
  components: Component[];
  totalConnections: number;
  bidirectionalConnections: number;
}

class PhiCalculator {
  private system: SystemState;

  constructor(system: SystemState) {
    this.system = system;
  }

  /**
   * Calculate simplified phi for the system
   * Returns a "phi-like" measure where > 0 suggests integration
   */
  calculatePhi(): { phi: number; details: any } {
    // 1. Calculate total system state space
    const totalSystemStates = this.system.components.reduce(
      (acc, c) => acc * c.stateSpaceSize, 
      1
    );
    const systemEntropy = Math.log2(totalSystemStates);

    // 2. Calculate partitioned state space (assuming minimal partition)
    // In full IIT, this tests ALL possible partitions - computationally intractable
    // Here we use a simplified approach: partition by cutting weakest connections
    const partitionResults = this.calculateOptimalPartition();
    
    // 3. Phi = System Entropy - Partitioned Entropies
    // When system is truly integrated, partitioned entropy is much lower
    const partitionedEntropy = partitionResults.entropySum;
    
    // 4. Calculate raw phi
    const rawPhi = systemEntropy - partitionedEntropy;
    
    // 5. Normalize by system size to get comparable metric
    const normalizedPhi = rawPhi / this.system.components.length;
    
    // 6. Integration coefficient (0-1) - connectivity factor
    const maxPossibleConnections = this.system.components.length * (this.system.components.length - 1);
    const connectivityRatio = this.system.totalConnections / maxPossibleConnections;
    const bidirectionalRatio = this.system.bidirectionalConnections / (this.system.totalConnections / 2);
    const integrationCoeff = connectivityRatio * (0.5 + 0.5 * bidirectionalRatio);

    return {
      phi: Math.max(0, normalizedPhi * integrationCoeff),
      details: {
        systemEntropy,
        partitionedEntropy,
        rawPhi,
        normalizedPhi,
        integrationCoefficient: integrationCoeff,
        partitionStrategy: partitionResults.strategy,
        componentCount: this.system.components.length,
        totalConnections: this.system.totalConnections,
        bidirectionalConnections: this.system.bidirectionalConnections
      }
    };
  }

  private calculateOptimalPartition(): { entropySum: number; strategy: string } {
    // Simplified: Find partition that maximizes difference (minimizes partitioned entropy)
    // This is a heuristic - full IIT would test all possible partitions
    
    const n = this.system.components.length;
    
    // Strategy 1: Cut components with fewest connections
    const byConnectivity = [...this.system.components]
      .sort((a, b) => (a.inputs.length + a.outputs.length) - (b.inputs.length + b.outputs.length));
    
    // Partition into 2 groups based on connectivity
    const group1Size = Math.ceil(n / 2);
    const group1 = byConnectivity.slice(0, group1Size);
    const group2 = byConnectivity.slice(group1Size);
    
    const g1States = group1.reduce((acc, c) => acc * c.stateSpaceSize, 1);
    const g2States = group2.reduce((acc, c) => acc * c.stateSpaceSize, 1);
    
    const entropySum = Math.log2(g1States) + Math.log2(g2States);
    
    return {
      entropySum,
      strategy: `bisect-by-connectivity (${group1Size}/${n - group1Size})`
    };
  }

  /**
   * Calculate effective information (EI) - another IIT concept
   * EI = How much past states constrain future states
   */
  calculateEffectiveInformation(): number {
    // Simplified: Use connectivity patterns as proxy for causal constraints
    const avgInputs = this.system.components.reduce((acc, c) => acc + c.inputs.length, 0) / this.system.components.length;
    const avgOutputs = this.system.components.reduce((acc, c) => acc + c.outputs.length, 0) / this.system.components.length;
    
    // Higher values mean more causal structure
    return (avgInputs + avgOutputs) / 2;
  }
}

